class Solution:
    def minimumLength(self, s):
        chars = list(s)
        changed = True
        while changed and len(chars) > 1 and chars[0] == chars[-1]:
            c = chars[0]
            i = 0
            while i < len(chars) and chars[i] == c:
                i += 1
            j = len(chars) - 1
            while j >= 0 and chars[j] == c:
                j -= 1
            if i > j:
                return 0
            chars = chars[i:j + 1]
        return len(chars)

