class Solution:
    def minimumLength(self, s):
        l, r = 0, len(s) - 1
        while l < r and s[l] == s[r]:
            c = s[l]
            while l <= r and s[l] == c:
                l += 1
            while r >= l and s[r] == c:
                r -= 1
        return max(0, r - l + 1)

