var minimumLength = function(s) {
    let l = 0, r = s.length - 1;
    while (l < r && s[l] === s[r]) {
        const c = s[l];
        while (l <= r && s[l] === c) l++;
        while (r >= l && s[r] === c) r--;
    }
    return Math.max(0, r - l + 1);
};
